import{_ as d,o as i,c as s,ag as c}from"./chunks/framework.CAXxHpAX.js";const b=JSON.parse('{"title":"中共一大：1921年，上海-嘉兴。中共成","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-33.md","filePath":"notes/note-33.md"}'),l={name:"notes/note-33.md"};function v(r,a,e,o,t,n){return i(),s("div",null,[...a[0]||(a[0]=[c('<h1 id="中共一大-1921年-上海-嘉兴。中共成" tabindex="-1">中共一大：1921年，上海-嘉兴。中共成 <a class="header-anchor" href="#中共一大-1921年-上海-嘉兴。中共成" aria-label="Permalink to &quot;中共一大：1921年，上海-嘉兴。中共成&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、中共一大：</span>1921年，上海-嘉兴。中共成立是开天辟地的大事变，自从有了中共，中国革命面貌就焕然一新。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、中共二大：</span>1922年。任务：打倒军阀、推翻帝国主义，将中国统一为真正的民主共和国。第一次提出明确反帝反封建革命纲领。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、中共三大：</span>1923年，广州。与国民党合作，建立革命统一战线。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、八七会议：</span>1927年，汉口。确定实行土地革命和武装反抗国民党反动派的方针，发动秋收起义，“政权是由枪杆子中取得的”。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、遵义会议：</span>1935年，遵义。纠正了“左”的错误，确立了以毛泽东为主要代表马克思主义正确路线在党中央的领导地位。生死攸关转折点。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、中共七大：</span>1945年，延安。毛泽东思想成为党的指导思想和入党章。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、中共七届二中全会：</span>1949年，西柏坡，党的工作重心从乡村转向城市；我国从落后农业国变先进工业国。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、中共八大：</span>1956年，北京。分析主要矛盾，任务是把我国从落后农业国变先进工业国。探索建设社会主义道路的良好开端。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、中共八大二次会议：</span>1958年，“鼓足干劲，力争上游，多快好省地建设社会主义”的总路线。（错误）</p></div><div class="circle-overlay"></div></div></div>',10)])])}const f=d(l,[["render",v]]);export{b as __pageData,f as default};
